#define MAX_N 100001

int tree[MAX_N];
int n;

void update(int i, int delta) {
    for (++i; i <= n; i += i & (-i))
        tree[i] += delta;
}

int query(int i) {
    int sum = 0;
    for (++i; i > 0; i -= i & (-i))
        sum += tree[i];
