int* fenwick_tree_operations(int arr[], int size, int* out_size) {
    if (size < 1) {
        *out_size = 0;
        return NULL;
    }

    int len = arr[0];
    if (len < 0 || size < 1 + len) {
        *out_size = 0;
        return NULL;
    }

    int remaining = size - 1 - len;
    if (remaining < 0 || (remaining % 3) != 0) {
        *out_size = 0;
        return NULL;
    }

    int q = remaining / 3;
    int* result = (int*)malloc((q > 0 ? q : 1) * sizeof(int));
    if (!result) {
        *out_size = 0;
        return NULL;
    }

    int* values = (int*)malloc((len > 0 ? len : 1) * sizeof(int));
    if (!values) {
        free(result);
        *out_size = 0;
        return NULL;
    }

    for (int i = 0; i < len; i++) {
        values[i] = arr[1 + i];
    }
    build(values, len);
    int pos = 1 + len;
    int result_count = 0;
    for (int i = 0; i < q; i++) {
        int type = arr[pos++];
        int a = arr[pos++];
        int b = arr[pos++];
        if (type == 1) {
            int delta = b - values[a];
            values[a] = b;
            update(a, delta);
        } else {
            result[result_count++] = query(a);
        }
    }

    free(values);
    *out_size = result_count;
    return result;
}

