struct FenwickTree {
    tree: Vec<i64>,
    n: usize,
}

impl FenwickTree {
    fn new(arr: &[i64]) -> Self {
        let n = arr.len();
        let mut ft = FenwickTree {
            tree: vec![0; n + 1],
            n,
        };
        for (i, &v) in arr.iter().enumerate() {
            ft.update(i, v);
        }
        ft
    }

    fn update(&mut self, idx: usize, delta: i64) {
        let mut i = idx + 1;
        while i <= self.n {
            self.tree[i] += delta;
            i += i & i.wrapping_neg();
        }
    }

    fn query(&self, idx: usize) -> i64 {
        let mut sum = 0;
        let mut i = idx + 1;
        while i > 0 {
            sum += self.tree[i];
            i -= i & i.wrapping_neg();
        }
        sum
    }
}

